#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <fcntl.h>

void create_daemon() {
 pid_t pid;

 // Step 1: Fork to create child process
 pid = fork();
 if (pid < 0) {
 exit(EXIT_FAILURE);
 }
 if (pid > 0) {
 // Parent exits
 exit(EXIT_SUCCESS);
 }

 // Step 2: Create new session
 if (setsid() < 0) {
 exit(EXIT_FAILURE);
 }

 // Step 3: Optional second fork
 pid = fork();
 if (pid < 0) {
 exit(EXIT_FAILURE);
 }
 if (pid > 0) {
 exit(EXIT_SUCCESS);
 }

 // Step 4: Change working directory to root
 chdir("/");

 // Step 5: Close standard file descriptors
 close(STDIN_FILENO);
 close(STDOUT_FILENO);
 close(STDERR_FILENO);

 // Redirect to /dev/null
 open("/dev/null", O_RDONLY);
 open("/dev/null", O_WRONLY);
 open("/dev/null", O_WRONLY);

 // Step 6: Set appropriate umask
 umask(0);
}

int main() {
 create_daemon();

 // Daemon work - infinite loop
 while (1) {
 // Daemon operations here
 sleep(60);
 }

 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <signal.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <fcntl.h>
#include <time.h>

#define PID_FILE "/var/run/mydaemon.pid"
static volatile int keep_running = 1;

void signal_handler(int sig) {
 if (sig == SIGTERM || sig == SIGINT) {
 keep_running = 0;
 }
}

void write_pid_file() {
 FILE *fp = fopen(PID_FILE, "w");
 if (fp) {
 fprintf(fp, "%d\n", getpid());
 fclose(fp);
 }
}

void daemon_work() {
 time_t now;
 FILE *log = fopen("/var/log/mydaemon.log", "a");

 while (keep_running) {
 time(&now);
 if (log) {
 fprintf(log, "Daemon running: %s", ctime(&now));
 fflush(log);
 }
 sleep(60);
 }

 if (log) fclose(log);
}

int main() {
 pid_t pid = fork();

 if (pid < 0) exit(EXIT_FAILURE);
 if (pid > 0) exit(EXIT_SUCCESS);

 setsid();
 chdir("/");
 umask(0);

 close(STDIN_FILENO);
 close(STDOUT_FILENO);
 close(STDERR_FILENO);

 signal(SIGTERM, signal_handler);
 signal(SIGINT, signal_handler);

 write_pid_file();
 daemon_work();

 unlink(PID_FILE);
 return 0;
}
